import{_ as t,o,c as i,ag as a}from"./chunks/framework.NsnsQ6zO.js";const p=JSON.parse('{"title":"AgentVM Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md"}'),r={name:"roadmap.md"};function n(l,e,s,d,c,h){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="agentvm-roadmap" tabindex="-1">AgentVM Roadmap <a class="header-anchor" href="#agentvm-roadmap" aria-label="Permalink to &quot;AgentVM Roadmap&quot;">​</a></h1><blockquote><p><strong>Building in public.</strong> Every milestone, every decision, every trade-off — documented here.</p><p>Last updated: May 2026</p></blockquote><hr><h2 id="release-timeline" tabindex="-1">Release Timeline <a class="header-anchor" href="#release-timeline" aria-label="Permalink to &quot;Release Timeline&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Codename</th><th>Target</th><th>Status</th></tr></thead><tbody><tr><td>v0.1.0</td><td><strong>Genesis</strong></td><td>Q2 2026</td><td>✅ Released</td></tr><tr><td>v0.2.x</td><td><strong>Ignition</strong></td><td>Q2 2026</td><td>✅ Released (v0.2.3)</td></tr><tr><td>v0.3.0</td><td><strong>Bridge</strong></td><td>Q3 2026</td><td>✅ Released</td></tr><tr><td>v1.0.0</td><td><strong>Launch</strong></td><td>Q1 2027</td><td>⬜ Planned</td></tr></tbody></table><hr><h2 id="phase-1-—-genesis-v0-1-0-✅" tabindex="-1">Phase 1 — Genesis (v0.1.0) ✅ <a class="header-anchor" href="#phase-1-—-genesis-v0-1-0-✅" aria-label="Permalink to &quot;Phase 1 — Genesis (v0.1.0) ✅&quot;">​</a></h2><p><strong>Goal:</strong> A working kernel that can spawn, manage, and terminate agent processes with in-memory state.</p><p><strong>Motto:</strong> <em>&quot;Make it work.&quot;</em></p><h3 id="shipped" tabindex="-1">Shipped <a class="header-anchor" href="#shipped" aria-label="Permalink to &quot;Shipped&quot;">​</a></h3><ul><li>[x] <code>Kernel</code> class — agent registry, process lifecycle, event system</li><li>[x] <code>Agent</code> definition — name, description, config, capability declarations</li><li>[x] <code>Process</code> model — spawn, pause, resume, terminate with state transitions</li><li>[x] Process states: <code>created → starting → running → paused → terminated → crashed</code></li><li>[x] Event emitter — all lifecycle events fire structured <code>KernelEvent</code> objects</li><li>[x] In-memory process store</li><li>[x] <code>MemoryBus</code> — namespaced key-value store, shared namespace, TTL support</li><li>[x] CLI scaffold: <code>agentvm init</code>, <code>start</code>, <code>spawn</code>, <code>ps</code>, <code>kill</code>, <code>logs</code></li><li>[x] TypeScript SDK with full type inference</li><li>[x] Unit tests for all core modules</li><li>[x] RFC-001 (Process State Machine Design) — accepted</li><li>[x] Architecture Overview, Getting Started guide, Contributing guide</li><li>[x] GitHub Actions CI/CD</li></ul><hr><h2 id="phase-2-—-ignition-v0-2-x-✅" tabindex="-1">Phase 2 — Ignition (v0.2.x) ✅ <a class="header-anchor" href="#phase-2-—-ignition-v0-2-x-✅" aria-label="Permalink to &quot;Phase 2 — Ignition (v0.2.x) ✅&quot;">​</a></h2><p><strong>Goal:</strong> Tool routing, message passing, scheduling, and LLM integration turn AgentVM into a real multi-agent runtime.</p><p><strong>Motto:</strong> <em>&quot;Make it useful.&quot;</em></p><h3 id="shipped-in-v0-2-0" tabindex="-1">Shipped in v0.2.0 <a class="header-anchor" href="#shipped-in-v0-2-0" aria-label="Permalink to &quot;Shipped in v0.2.0&quot;">​</a></h3><ul><li>[x] <code>ToolRouter</code> — registry, invocation, rate limiting, permission checks</li><li>[x] <code>MessageBroker</code> — pub/sub channels, direct messaging, priority, history, dead-letter handling</li><li>[x] <code>Scheduler</code> — sequential, parallel, race, conditional strategies with dependency resolution and retry</li><li>[x] <code>Kernel.execute()</code> — <code>ExecutionContext</code> with memory, tools, publish, emit, AbortSignal</li><li>[x] Agent tool allowlist enforcement</li><li>[x] RFC-002 (Memory Bus Interface Contract) — accepted</li><li>[x] RFC-003 (Event Schema Specification) — accepted</li></ul><h3 id="shipped-in-v0-2-1" tabindex="-1">Shipped in v0.2.1 <a class="header-anchor" href="#shipped-in-v0-2-1" aria-label="Permalink to &quot;Shipped in v0.2.1&quot;">​</a></h3><ul><li>[x] <code>AgentContract</code> types — typed input/output, SLA fields (<code>maxLatency</code>, <code>maxCost</code>)</li><li>[x] <code>Kernel.registerTool()</code> and <code>Kernel.createChannel()</code> convenience methods</li><li>[x] <code>MemoryBus.stats</code>, <code>MessageBroker.stats</code>, <code>Scheduler.stats</code></li><li>[x] Idempotent <code>Process._terminate()</code></li><li>[x] Scoped rate limit counters (per agent, not global)</li></ul><h3 id="shipped-in-v0-2-2" tabindex="-1">Shipped in v0.2.2 <a class="header-anchor" href="#shipped-in-v0-2-2" aria-label="Permalink to &quot;Shipped in v0.2.2&quot;">​</a></h3><ul><li>[x] <code>MCPClient</code> — stdio + SSE transports, JSON-RPC 2.0, auto-registers MCP tools</li><li>[x] <code>createLLMAgent()</code> — Anthropic + OpenAI, agentic tool loop, conversation history, token tracking</li><li>[x] <code>createPipeline()</code> — sequential multi-agent pipeline helper</li><li>[x] Built-in tools: <code>http_fetch</code>, <code>json_fetch</code>, <code>shell_exec</code>, <code>file_read</code>, <code>file_write</code>, <code>wait</code></li><li>[x] <code>registerBuiltins(kernel)</code> convenience function</li><li>[x] Example projects: <code>llm-pipeline.ts</code>, <code>mcp-agent.ts</code>, <code>llm-research-agent.ts</code></li><li>[x] Tests for LLM agent and MCP client</li></ul><hr><h2 id="phase-3-—-bridge-v0-3-0-✅" tabindex="-1">Phase 3 — Bridge (v0.3.0) ✅ <a class="header-anchor" href="#phase-3-—-bridge-v0-3-0-✅" aria-label="Permalink to &quot;Phase 3 — Bridge (v0.3.0) ✅&quot;">​</a></h2><p><strong>Goal:</strong> Persistent state, runtime contract enforcement, config system, and framework adapters.</p><p><strong>Motto:</strong> <em>&quot;Make it connect.&quot;</em></p><h3 id="milestones" tabindex="-1">Milestones <a class="header-anchor" href="#milestones" aria-label="Permalink to &quot;Milestones&quot;">​</a></h3><h4 id="m3-1-—-config-system-✅" tabindex="-1">M3.1 — Config System ✅ <a class="header-anchor" href="#m3-1-—-config-system-✅" aria-label="Permalink to &quot;M3.1 — Config System ✅&quot;">​</a></h4><ul><li>[x] YAML config file (<code>agentvm.yml</code>) — declare agents, tools, channels declaratively</li><li>[x] Built-in YAML parser (zero dependencies)</li><li>[x] Environment variable overrides via <code>env:</code> section</li><li>[x] Config validation on startup with helpful error messages (<code>ConfigValidationError</code>)</li><li>[ ] Hot-reload for non-breaking config changes</li><li>[ ] <code>agentvm validate</code> CLI command</li></ul><h4 id="m3-2-—-persistent-memory-backends-✅" tabindex="-1">M3.2 — Persistent Memory Backends ✅ <a class="header-anchor" href="#m3-2-—-persistent-memory-backends-✅" aria-label="Permalink to &quot;M3.2 — Persistent Memory Backends ✅&quot;">​</a></h4><ul><li>[x] <code>MemoryBackend</code> interface — stable contract all backends implement (8 methods)</li><li>[x] <code>InMemoryBackend</code> — refactored default, backward compatible</li><li>[x] <code>SqliteBackend</code> — embedded, zero-config, file-based persistence via sql.js (pure WASM)</li><li>[x] <code>MemoryBus</code> accepts pluggable backends via constructor</li><li>[x] <code>Kernel</code> accepts <code>memoryBackend</code> in config</li><li>[ ] Redis backend — distributed cache + pub/sub, connection pooling</li><li>[ ] Migration utility — move memory data between backends</li></ul><h4 id="m3-3-—-agent-contract-enforcement-✅" tabindex="-1">M3.3 — Agent Contract Enforcement ✅ <a class="header-anchor" href="#m3-3-—-agent-contract-enforcement-✅" aria-label="Permalink to &quot;M3.3 — Agent Contract Enforcement ✅&quot;">​</a></h4><ul><li>[x] Runtime input validation against <code>AgentContract.input</code> schema</li><li>[x] Runtime output validation against <code>AgentContract.output</code> schema</li><li>[x] <code>validateSchema()</code> — recursive validator for string/number/boolean/object/array</li><li>[x] <code>ContractValidationError</code> with agent name, phase, and violation details</li><li>[x] SLA enforcement — emits <code>contract:sla:latency</code> event when <code>maxLatency</code> exceeded</li><li>[ ] <code>Pipeline</code> validates type compatibility between chained agents at construction time</li><li>[ ] RFC-004 (Agent Contract Enforcement) — in progress</li></ul><h4 id="m3-4-—-resource-tracking-✅" tabindex="-1">M3.4 — Resource Tracking ✅ <a class="header-anchor" href="#m3-4-—-resource-tracking-✅" aria-label="Permalink to &quot;M3.4 — Resource Tracking ✅&quot;">​</a></h4><ul><li>[x] Surface <code>tokensUsed</code> on <code>ExecutionResult</code> automatically from <code>__llm_usage</code></li><li>[x] LLM agent propagates <code>__llm_usage</code> to <code>ExecutionResult</code> automatically</li><li>[x] <code>Kernel.stats()</code> — aggregate stats: agents, processes by state, memory, tools, channels, total tokens</li><li>[ ] Per-process token budget — abort execution when limit exceeded</li><li>[ ] Surface <code>cost</code> on <code>ExecutionResult</code></li></ul><h4 id="m3-5-—-checkpointing-✅" tabindex="-1">M3.5 — Checkpointing ✅ <a class="header-anchor" href="#m3-5-—-checkpointing-✅" aria-label="Permalink to &quot;M3.5 — Checkpointing ✅&quot;">​</a></h4><ul><li>[x] <code>checkpoint(kernel, processId, path)</code> — serialize process metadata + memory to JSON</li><li>[x] <code>restore(kernel, path)</code> — spawn process and restore all memory from checkpoint</li><li>[x] <code>readCheckpoint(path)</code> — inspect checkpoint data without restoring</li><li>[ ] Automatic checkpoint on crash</li><li>[ ] RFC-005 (Checkpointing Strategy) — planned</li></ul><h4 id="m3-6-—-framework-adapters-✅" tabindex="-1">M3.6 — Framework Adapters ✅ <a class="header-anchor" href="#m3-6-—-framework-adapters-✅" aria-label="Permalink to &quot;M3.6 — Framework Adapters ✅&quot;">​</a></h4><ul><li>[x] LangChain.js adapter — tools (<code>toLangChainTools</code>) + memory (<code>toLangChainMemory</code>)</li><li>[x] Vercel AI SDK adapter — tools (<code>toAISDKTools</code>) + usage tracking (<code>createUsageTracker</code>)</li><li>[x] Generic adapter — OpenAI format, Anthropic format, tool executor, MCP server (<code>serveMCP</code>)</li><li>[x] <code>describeTools()</code> debug helper</li><li>[x] Adapter test suite (34 tests)</li><li>[ ] CrewAI adapter (Python-only framework — out of scope for JS SDK)</li></ul><h3 id="phase-3-rfcs" tabindex="-1">Phase 3 RFCs <a class="header-anchor" href="#phase-3-rfcs" aria-label="Permalink to &quot;Phase 3 RFCs&quot;">​</a></h3><ul><li><code>RFC-004</code> — Agent Contract Enforcement</li><li><code>RFC-005</code> — Checkpointing Strategy</li><li><code>RFC-006</code> — Persistent Memory Backend Interface</li></ul><hr><h2 id="phase-4-—-launch-v1-0-0" tabindex="-1">Phase 4 — Launch (v1.0.0) <a class="header-anchor" href="#phase-4-—-launch-v1-0-0" aria-label="Permalink to &quot;Phase 4 — Launch (v1.0.0)&quot;">​</a></h2><p><strong>Goal:</strong> Production-grade, distributed, and battle-tested.</p><p><strong>Motto:</strong> <em>&quot;Make it scale.&quot;</em></p><h3 id="milestones-1" tabindex="-1">Milestones <a class="header-anchor" href="#milestones-1" aria-label="Permalink to &quot;Milestones&quot;">​</a></h3><h4 id="m4-1-—-distributed-mode" tabindex="-1">M4.1 — Distributed Mode <a class="header-anchor" href="#m4-1-—-distributed-mode" aria-label="Permalink to &quot;M4.1 — Distributed Mode&quot;">​</a></h4><ul><li>[ ] Multi-node kernel clusters</li><li>[ ] Process migration between nodes</li><li>[ ] Distributed message broker (NATS integration)</li><li>[ ] Shared state across nodes (CRDTs or distributed locks)</li><li>[ ] Node discovery and health monitoring</li></ul><h4 id="m4-2-—-kubernetes-operator" tabindex="-1">M4.2 — Kubernetes Operator <a class="header-anchor" href="#m4-2-—-kubernetes-operator" aria-label="Permalink to &quot;M4.2 — Kubernetes Operator&quot;">​</a></h4><ul><li>[ ] Custom Resource Definitions (CRDs) for agents and workflows</li><li>[ ] Auto-scaling based on task queue depth</li><li>[ ] Rolling updates for agent definitions</li><li>[ ] Helm chart for easy deployment</li></ul><h4 id="m4-3-—-admin-dashboard" tabindex="-1">M4.3 — Admin Dashboard <a class="header-anchor" href="#m4-3-—-admin-dashboard" aria-label="Permalink to &quot;M4.3 — Admin Dashboard&quot;">​</a></h4><ul><li>[ ] Web UI for monitoring all running processes</li><li>[ ] Real-time event stream visualization</li><li>[ ] Resource consumption graphs</li><li>[ ] Tool usage analytics</li><li>[ ] Channel activity monitor</li><li>[ ] Process management (spawn/kill from UI)</li></ul><h4 id="m4-4-—-hardening" tabindex="-1">M4.4 — Hardening <a class="header-anchor" href="#m4-4-—-hardening" aria-label="Permalink to &quot;M4.4 — Hardening&quot;">​</a></h4><ul><li>[ ] Performance benchmarks (latency, throughput, memory)</li><li>[ ] Load testing at 1000+ concurrent agents</li><li>[ ] Security audit (tool permissions, sandbox escapes, injection)</li><li>[ ] API stability guarantee — semantic versioning commitment</li><li>[ ] Comprehensive documentation site</li><li>[ ] Python SDK</li></ul><h3 id="phase-4-rfcs" tabindex="-1">Phase 4 RFCs <a class="header-anchor" href="#phase-4-rfcs" aria-label="Permalink to &quot;Phase 4 RFCs&quot;">​</a></h3><ul><li><code>RFC-007</code> — Distributed Consensus Model</li><li><code>RFC-008</code> — Kubernetes CRD Specification</li><li><code>RFC-009</code> — Dashboard Architecture</li><li><code>RFC-010</code> — v1.0 API Stability Contract</li></ul><hr><h2 id="feature-requests-voting" tabindex="-1">Feature Requests &amp; Voting <a class="header-anchor" href="#feature-requests-voting" aria-label="Permalink to &quot;Feature Requests &amp; Voting&quot;">​</a></h2><p>We use GitHub Discussions for feature requests. The community votes on what gets built next.</p><p><strong>How to propose a feature:</strong></p><ol><li>Open a Discussion in the &quot;Feature Requests&quot; category</li><li>Describe the problem, proposed solution, and alternatives</li><li>Community votes with 👍</li><li>Top-voted features get added to the next phase</li></ol><p><strong>How to propose an architectural change:</strong></p><ol><li>Write an RFC in <code>docs/rfcs/</code> using the template in <code>RFC-000-TEMPLATE.md</code></li><li>Open a PR</li><li>Community reviews and discusses</li><li>Maintainers approve or request changes</li><li>Approved RFCs get scheduled into a phase</li></ol><hr><h2 id="build-in-public-log" tabindex="-1">Build in Public Log <a class="header-anchor" href="#build-in-public-log" aria-label="Permalink to &quot;Build in Public Log&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Date</th><th>Decision</th><th>Context</th></tr></thead><tbody><tr><td>2026-03-26</td><td>Project kickoff</td><td>Repository created, roadmap published</td></tr><tr><td>2026-03-31</td><td>v0.2.0 released</td><td>ToolRouter, MessageBroker, Scheduler, Kernel.execute()</td></tr><tr><td>2026-04-05</td><td>v0.2.1 released</td><td>AgentContract types, convenience methods, bug fixes</td></tr><tr><td>2026-04-11</td><td>v0.2.2 released</td><td>MCPClient, createLLMAgent, built-in tools, pipeline helper</td></tr><tr><td>2026-05-05</td><td>v0.3.0 released</td><td>MemoryBackend interface, SQLite backend, contract enforcement, config system, checkpointing, Kernel.stats()</td></tr><tr><td>2026-05-05</td><td>Framework adapters</td><td>LangChain.js, Vercel AI SDK, and generic (OpenAI/Anthropic/MCP) adapters shipped</td></tr></tbody></table><blockquote><p>This log is updated with every major decision. Subscribe to releases to get notified.</p></blockquote><hr><h2 id="how-to-get-involved" tabindex="-1">How to Get Involved <a class="header-anchor" href="#how-to-get-involved" aria-label="Permalink to &quot;How to Get Involved&quot;">​</a></h2><ul><li><strong>Build:</strong> Pick an open issue and submit a PR</li><li><strong>Design:</strong> Write or review RFCs</li><li><strong>Test:</strong> Try the latest release and report bugs</li><li><strong>Spread:</strong> Star the repo, share on socials, write blog posts</li><li><strong>Discuss:</strong> Join GitHub Discussions or Discord</li></ul><p>Every contribution matters. Let&#39;s build this together.</p>',70)])])}const m=t(r,[["render",n]]);export{p as __pageData,m as default};
